import { useState, useEffect } from "react";
import { FaPlus, FaTrash, FaCalculator, FaPrint, FaUser, FaPhoneAlt } from "react-icons/fa";

// ── Configuration ────────────────────────────────────────────────────────────
const STORAGE_KEY = "dcl_master_store";
const PRICE_KEY = "dcl_prices";

// Fallback defaults if the Owner hasn't set prices yet
const DEFAULT_PRICES = {
  "Wash & Fold": 15.00,
  "Dry Cleaning": 25.00,
  "Ironing Only": 10.00,
  "Duvet/Large": 35.00
};

export default function POSView() {
  // 1. Load Prices set by Owner (Logic Update Only)
  const [activePrices, setActivePrices] = useState(() => {
    const saved = localStorage.getItem(PRICE_KEY);
    return saved ? JSON.parse(saved) : DEFAULT_PRICES;
  });

  const [cart, setCart] = useState([]);
  const [customer, setCustomer] = useState({ name: "", phone: "" });

  // 2. Calculate Total (Logic Update Only)
  const totalAmount = cart.reduce((sum, item) => sum + item.price, 0);

  const addToCart = (service) => {
    const newItem = {
      id: Date.now(),
      name: service,
      price: activePrices[service] || 0
    };
    setCart([...cart, newItem]);
  };

  const removeFromCart = (id) => {
    setCart(cart.filter(item => item.id !== id));
  };

  return (
    <div style={S.container}>
      <div style={S.grid}>
        
        {/* LEFT: Service Menu */}
        <div className="glass" style={S.section}>
          <h3 style={S.title}>Service Menu</h3>
          <p style={S.subtitle}>Select services to add to order</p>
          <div style={S.menuList}>
            {Object.keys(activePrices).map((service) => (
              <div key={service} style={S.serviceCard} onClick={() => addToCart(service)}>
                <div style={{ flex: 1 }}>
                  <div style={S.serviceName}>{service}</div>
                  <div style={S.priceTag}>${activePrices[service].toFixed(2)}</div>
                </div>
                <div style={S.addIcon}><FaPlus /></div>
              </div>
            ))}
          </div>
        </div>

        {/* RIGHT: Cart & Checkout */}
        <div className="glass" style={S.section}>
          <h3 style={S.title}>Current Order</h3>
          
          <div style={S.customerInfo}>
             <div style={S.inputField}><FaUser/><input placeholder="Customer Name" value={customer.name} onChange={e => setCustomer({...customer, name: e.target.value})} style={S.bareInput}/></div>
             <div style={S.inputField}><FaPhoneAlt/><input placeholder="Phone Number" value={customer.phone} onChange={e => setCustomer({...customer, phone: e.target.value})} style={S.bareInput}/></div>
          </div>

          <div style={S.cartArea}>
            {cart.length === 0 ? (
              <p style={S.empty}>Cart is empty</p>
            ) : (
              cart.map(item => (
                <div key={item.id} style={S.cartItem}>
                  <span>{item.name}</span>
                  <div style={{ display: "flex", alignItems: "center", gap: "10px" }}>
                    <b>${item.price.toFixed(2)}</b>
                    <button onClick={() => removeFromCart(item.id)} style={S.delBtn}><FaTrash/></button>
                  </div>
                </div>
              ))
            )}
          </div>

          <div style={S.footer}>
            <div style={S.totalRow}>
              <span>Total Amount:</span>
              <span style={S.totalPrice}>${totalAmount.toFixed(2)}</span>
            </div>
            <button style={S.checkoutBtn} disabled={cart.length === 0}>
              <FaPrint /> Process & Print Receipt
            </button>
          </div>
        </div>

      </div>
    </div>
  );
}

// ── UNCHANGED CSS STYLES ─────────────────────────────────────────────────────
const S = {
  container: { padding: "20px", color: "#fff" },
  grid: { display: "grid", gridTemplateColumns: "1.2fr 1fr", gap: "25px" },
  section: { background: "rgba(255,255,255,0.05)", padding: "25px", borderRadius: "20px", backdropFilter: "blur(10px)" },
  title: { margin: "0 0 5px" },
  subtitle: { fontSize: "12px", color: "rgba(255,255,255,0.4)", marginBottom: "20px" },
  menuList: { display: "grid", gridTemplateColumns: "1fr 1fr", gap: "15px" },
  serviceCard: { background: "rgba(255,255,255,0.03)", padding: "15px", borderRadius: "15px", border: "1px solid rgba(255,255,255,0.08)", cursor: "pointer", display: "flex", alignItems: "center", transition: "0.2s" },
  serviceName: { fontSize: "14px", fontWeight: "600" },
  priceTag: { color: "#00d4ff", fontSize: "13px", marginTop: "4px" },
  addIcon: { background: "#0077b6", padding: "8px", borderRadius: "8px", display: "flex" },
  customerInfo: { marginBottom: "20px" },
  inputField: { display: "flex", alignItems: "center", gap: "10px", background: "rgba(0,0,0,0.2)", padding: "12px", borderRadius: "10px", marginBottom: "8px" },
  bareInput: { background: "transparent", border: "none", color: "#fff", outline: "none", width: "100%" },
  cartArea: { minHeight: "200px", borderTop: "1px solid rgba(255,255,255,0.1)", paddingTop: "15px" },
  cartItem: { display: "flex", justifyContent: "space-between", marginBottom: "10px", fontSize: "14px" },
  delBtn: { background: "none", border: "none", color: "#ef4444", cursor: "pointer" },
  empty: { textAlign: "center", color: "rgba(255,255,255,0.2)", marginTop: "50px" },
  footer: { marginTop: "20px", borderTop: "2px dashed rgba(255,255,255,0.1)", paddingTop: "20px" },
  totalRow: { display: "flex", justifyContent: "space-between", marginBottom: "15px", fontSize: "18px", fontWeight: "800" },
  totalPrice: { color: "#00d4ff" },
  checkoutBtn: { width: "100%", padding: "15px", borderRadius: "12px", border: "none", background: "#10b981", color: "#fff", fontWeight: "700", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: "10px" }
};
